import{_ as t,o,c as a,Q as r}from"./chunks/framework.32dba02b.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Computer/DB/theory.md","filePath":"Computer/DB/theory.md","lastUpdated":1697443096000}'),e={name:"Computer/DB/theory.md"},p=r('<h2 id="cap-理论" tabindex="-1">CAP 理论 <a class="header-anchor" href="#cap-理论" aria-label="Permalink to &quot;CAP 理论&quot;">​</a></h2><p><strong>C（Consistency）一致性</strong></p><p>任何一个读操作总是能够读到之前完成的写操作的结果，也就是在分布式环境中，多点的数据是一致的，或者说，所有节点在同一时间具有相同的数据。</p><p><strong>A（Availability）可用性</strong></p><p>快速获取数据，可以在确定的时间内返回操作结果，保证每个请求不管成功或者失败都有响应。</p><p><strong>P（Tolerance of Network Partition）分区容忍性</strong></p><p>当出现网络分区的情况时（即系统中的一部分节点无法和其他节点进行通信），分离的系统也能够正常运行，也就是说，系统中任意信息的丢失或失败不会影响系统的继续运作。</p><h2 id="acid-模型" tabindex="-1">ACID 模型 <a class="header-anchor" href="#acid-模型" aria-label="Permalink to &quot;ACID 模型&quot;">​</a></h2><p><strong>A (Atomicity) 原子性</strong></p><p>事务必须是原子工作单元，对于其数据修改，要么全都执行，要么全都不执行，只要有一个操作失败，整个事务就失败，需要回滚。</p><p><strong>C (Consistency) 一致性</strong></p><p>数据库要一直处于一致的状态，事务的运行不会改变数据库原本的一致性约束。</p><p><strong>I (Isolation) 独立性</strong></p><p>并发的事务之间不会互相影响，如果一个事务要访问的数据正在被另外一个事务修改，只要另外一个事务未提交，它所访问的数据就不受未提交事务的影响。</p><p><strong>D (Durability) 持久性</strong></p><p>一旦事务提交后，它所做的修改将会永久的保存在数据库上，即使出现宕机也不会丢失。</p><h2 id="base-模型" tabindex="-1">BASE 模型 <a class="header-anchor" href="#base-模型" aria-label="Permalink to &quot;BASE 模型&quot;">​</a></h2><p><strong>BA（Basically Availble）基本可用</strong></p><p>是指一个分布式系统的一部分发生问题变得不可用时，其他部分仍然可以正常使用，也就是允许分区失败的情形出现。</p><p><strong>S（Soft-state）软状态</strong></p><p>“软状态（soft-state）”是与“硬状态（hard-state）”相对应的一种提法。数据库保存的数据是“硬状态”时，可以保证数据一致性，即保证数据一直是正确的。“软状态”是指状态可以有一段时间不同步，具有一定的滞后性。</p><p><strong>E（Eventual consistency）最终一致性</strong></p><p>一致性的类型包括强一致性和弱一致性，二者的主要区别在于高并发的数据访问操作下，后续操作是否能够获取最新的数据。对于强一致性而言，当执行完一次更新操作后，后续的其他读操作就可以保证读到更新后的最新数据；反之，如果不能保证后续访问读到的都是更新后的最新数据，那么就是弱一致性。而最终一致性只不过是弱一致性的一种特例，允许后续的访问操作可以暂时读不到更新后的数据，但是经过一段时间之后，必须最终读到更新后的数据。</p><h2 id="最终一致性" tabindex="-1">最终一致性 <a class="header-anchor" href="#最终一致性" aria-label="Permalink to &quot;最终一致性&quot;">​</a></h2><p><strong>因果一致性</strong></p><p>如果进程A通知进程B它已更新了一个数据项，那么进程B的后续访问将获得A写入的最新值。而与进程A无因果关系的进程C的访问，仍然遵守一般的最终一致性规则。</p><p><strong>“读己之所写”一致性</strong></p><p>可以视为因果一致性的一个特例。当进程A自己执行一个更新操作之后，它自己总是可以访问到更新过的值，绝不会看到旧值。</p><p><strong>单调读一致性</strong></p><p>如果进程已经看到过数据对象的某个值，那么任何后续访问都不会返回在那个值之前的值。</p><p><strong>会话一致性</strong></p><p>它把访问存储系统的进程放到会话（session）的上下文中，只要会话还存在，系统就保证“读己之所写”一致性。如果由于某些失败情形令会话终止，就要建立新的会话，而且系统保证不会延续到新的会话。</p><p><strong>单调写一致性</strong></p><p>系统保证来自同一个进程的写操作顺序执行。系统必须保证这种程度的一致性，否则就非常难以编程了。</p>',34),s=[p];function n(i,c,l,g,h,d){return o(),a("div",null,s)}const u=t(e,[["render",n]]);export{A as __pageData,u as default};
